type FieldPackerServer struct {
	pb.UnimplementedFieldPackerServiceServer
	Ctx     *app.Context
	Handles *handlestore.HandleStore
}

func (s *FieldPackerServer) NewFieldPacker(_ context.Context, req *pb.NewFieldPackerRequest) (*pb.NewFieldPackerResponse, error) {
	obj, err := jnipkg.NewFieldPacker(s.Ctx.VM, s.Handles.Get(req.GetArg0()))
	if err != nil {
		return nil, status.Errorf(codes.Internal, "create object: %v", err)
	}
	var handle int64
	if doErr := s.Ctx.VM.Do(func(env *jni.Env) error {
		handle = s.Handles.Put(env, obj.Obj)
		return nil
	}); doErr != nil {
		return nil, status.Errorf(codes.Internal, "store handle: %v", doErr)
	}
	return &pb.NewFieldPackerResponse{Result: handle}, nil
}

